detection.query:
event.category:"network" and destination.domain:* and network.protocol:"https"
and not destination.domain: (*.yourbank.com or *.windowsupdate.com or *.microsoft.com)
and source.ip: <file_server_subnet>
// Rank candidates by beacon regularity (low stddev of inter-request interval)
// and newly-registered-domain age < 30 days. Domain-age lookup absent in lab.
